#include "common/graph.h"

namespace delayed = parlay::block_delayed;

using vertexId = int;
using edgeId = uint;
using Graph = graph<vertexId, edgeId>;

// Build the transpose of a directed graph (parallel)
static Graph transpose_graph(const Graph& G) {
  const size_t n = G.numVertices();
  const size_t m = G.m;

  // Count in-degrees (i.e., degrees in GT)
  auto indeg = parlay::sequence<std::atomic<edgeId>>(n);
  parlay::parallel_for(0, n, [&](size_t i) { indeg[i].store(0, std::memory_order_relaxed); });
  parlay::parallel_for(0, n, [&](size_t u) {
    auto vtx = G[u];
    for (edgeId j = 0; j < (edgeId)vtx.degree; ++j) {
      vertexId v = vtx.Neighbors[j];
      indeg[v].fetch_add(1, std::memory_order_relaxed);
    }
  }, 1);

  // Convert to a normal sequence for prefix sums
  auto deg = parlay::tabulate(n, [&](size_t i) -> edgeId { return indeg[i].load(std::memory_order_relaxed); });

  // Exclusive prefix sum to offsets (sequential prefix-sum is fine; n << m typically)
  auto offsets = parlay::sequence<edgeId>(n + 1);
  offsets[0] = 0;
  for (size_t i = 0; i < n; ++i) offsets[i + 1] = offsets[i] + deg[i];

  // Fill transpose edges: for each edge u->v in G, insert u into GT[v]
  auto T_edges = parlay::sequence<vertexId>(m);
  // Positions start at offsets; use atomic counters for thread-safe fill
  auto next_pos = parlay::sequence<std::atomic<edgeId>>(n);
  parlay::parallel_for(0, n, [&](size_t i) { next_pos[i].store(offsets[i], std::memory_order_relaxed); });

  parlay::parallel_for(0, n, [&](size_t u) {
    auto vtx = G[u];
    for (edgeId j = 0; j < (edgeId)vtx.degree; ++j) {
      vertexId v = vtx.Neighbors[j];
      edgeId p = next_pos[v].fetch_add(1, std::memory_order_relaxed);
      T_edges[p] = (vertexId)u;
    }
  }, 1);

  return Graph(std::move(offsets), std::move(T_edges), n);
}

template <class GraphT>
static inline typename GraphT::edgeId frontier_out_edges(const GraphT& G,
                                                         const parlay::sequence<typename GraphT::vertexId>& frontier) {
  using E = typename GraphT::edgeId;
  return parlay::reduce(parlay::delayed_map(frontier, [&](auto u) -> E {
                          return (E)G[u].degree;
                        }),
                        parlay::addm<E>());
}

// Top-down expand: CAS on parent[v] and collect newly visited vertices
template <class GraphT>
static parlay::sequence<typename GraphT::vertexId>
topdown_expand(const GraphT& G,
               parlay::sequence<std::atomic<typename GraphT::vertexId>>& parent,
               const parlay::sequence<typename GraphT::vertexId>& frontier) {
  using V = typename GraphT::vertexId;

  // Flatten all edges incident to frontier
  auto nested = parlay::map(frontier, [&](V u) {
    auto vtx = G[u];
    return parlay::delayed_tabulate(vtx.degree, [=](size_t i) {
      return std::pair<V, V>(u, vtx.Neighbors[i]);
    });
  });
  auto edges = delayed::flatten(nested);

  // For each edge (u,v), if v is unvisited, set parent[v]=u via CAS and keep v
  auto next = delayed::filter_map(edges,
                                  [&](const std::pair<V, V>& e) {
                                    V v = e.second;
                                    if (parent[v].load(std::memory_order_relaxed) != -1) return false;
                                    V expected = (V)-1;
                                    return parent[v].compare_exchange_strong(expected, e.first,
                                                                             std::memory_order_relaxed);
                                  },
                                  [](const std::pair<V, V>& e) { return e.second; });
  return next;
}

// Simple parallel top-down BFS
parlay::sequence<vertexId> breadthFirstSearch(vertexId start, const Graph& G, bool verbose = false) {
  parlay::internal::timer t("breadthFirstSearch", verbose);
  const size_t n = G.numVertices();
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [&](size_t) {
    return (vertexId)-1;
  });
  parent[start].store(start, std::memory_order_relaxed);

  parlay::sequence<vertexId> frontier(1, start);
  t.next("init");

  while (!frontier.empty()) {
    frontier = topdown_expand(G, parent, frontier);
    if (verbose) t.next("iter");
  }

  return parlay::map(parent, [](const std::atomic<vertexId>& x) -> vertexId { return x.load(); });
}

// Direction-optimizing BFS (back-forward BFS): switches between top-down and bottom-up
parlay::sequence<vertexId> backForwardBFS(vertexId start, const Graph& G, bool verbose = false) {
  parlay::internal::timer t("backForwardBFS", verbose);
  const size_t n = G.numVertices();
  const size_t m = G.m;

  // Parent array: -1 unvisited, root points to itself
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [&](size_t) {
    return (vertexId)-1;
  });
  parent[start].store(start, std::memory_order_relaxed);

  // Build transpose for efficient bottom-up steps on directed graphs
  auto GT = transpose_graph(G);
  t.next("transpose");

  // Heuristics from Beamer et al. (SLAB-style switching)
  const double alpha = 15.0;
  const double beta  = 24.0;

  parlay::sequence<vertexId> frontier(1, start);
  bool use_bottom_up = false;

  // Remaining in-edges among unvisited vertices
  edgeId remaining_in_edges = (edgeId)m;
  remaining_in_edges -= (edgeId)GT[start].degree;
  size_t visited_vertices = 1;

  // Dense frontier marking for bottom-up
  auto dense_frontier = parlay::sequence<unsigned char>(n, (unsigned char)0);

  t.next("init");

  while (!frontier.empty()) {
    // Decide which direction to use this iteration
    if (!use_bottom_up) {
      edgeId frontier_work = frontier_out_edges(G, frontier);
      if (frontier_work > (remaining_in_edges / alpha)) use_bottom_up = true;
    } else {
      if (frontier.size() < n / beta) use_bottom_up = false;
    }

    parlay::sequence<vertexId> next;

    if (!use_bottom_up) {
      // Top-down
      next = topdown_expand(G, parent, frontier);
      if (verbose) t.next("topdown");
    } else {
      // Bottom-up:
      // 1) Mark frontier densely
      parlay::parallel_for(0, frontier.size(), [&](size_t i) {
        dense_frontier[frontier[i]] = (unsigned char)1;
      });

      // 2) For each unvisited vertex v, if any incoming neighbor is in frontier, visit v
      auto next_flags = parlay::sequence<bool>(n, false);
      parlay::parallel_for(0, n, [&](size_t v) {
        if (parent[v].load(std::memory_order_relaxed) == -1) {
          auto in_vtx = GT[v];
          for (edgeId j = 0; j < (edgeId)in_vtx.degree; ++j) {
            vertexId u = in_vtx.Neighbors[j];
            if (dense_frontier[u]) {
              parent[v].store(u, std::memory_order_relaxed);
              next_flags[v] = true;
              break;
            }
          }
        }
      }, 1);

      // 3) Clear dense frontier marks for those vertices
      parlay::parallel_for(0, frontier.size(), [&](size_t i) {
        dense_frontier[frontier[i]] = (unsigned char)0;
      });

      // 4) Pack next frontier
      next = parlay::pack_index<vertexId>(next_flags);
      if (verbose) t.next("bottomup");
    }

    if (next.empty()) break;

    // Update remaining in-edges after discovering "next"
    edgeId in_deg_of_next = parlay::reduce(parlay::delayed_map(next, [&](vertexId v) -> edgeId {
                               return (edgeId)GT[v].degree;
                             }),
                             parlay::addm<edgeId>());
    remaining_in_edges -= in_deg_of_next;
    visited_vertices += next.size();

    frontier = std::move(next);
    if (verbose) t.next("iter");
  }

  return parlay::map(parent, [](const std::atomic<vertexId>& x) -> vertexId { return x.load(); });
}

// Backward-forward (hybrid) BFS as the default BFS implementation
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  return backForwardBFS(start, G, verbose);
}
